cd /home/user/solid-octo-giggle && node -e "
const fs = require('fs');
const path = require('path');

const srcStat = fs.readdirSync('src', {recursive:true})
  .filter(f => /\\.(js|css)$/.test(f))
  .map(f => fs.statSync(path.join('src', f)).mtimeMs)
  .reduce((a, b) => Math.max(a, b), 0);

const ssDir = 'screenshots';
const ssStat = fs.existsSync(ssDir)
  ? fs.readdirSync(ssDir).filter(f => f.endsWith('.png'))
      .map(f => fs.statSync(path.join(ssDir, f)).mtimeMs)
      .reduce((a, b) => Math.max(a, b), 0)
  : 0;

if (srcStat > ssStat) {
  console.error('UI files changed but screenshots not refreshed. Run: npm run screenshot');
  process.exit(1);
}
"
